<template>
  <div>
    <div class="top-text">
      我们在一起{{ days }}天{{ h }}小时{{ m }}分钟{{ s }}秒
    </div>
    <div class="container">
      <div class="mobie heart heart-beat">
        <div class="heart heart-shadow"></div>
      </div>
    </div>
    <div class="bottom-text">
      <div class="name">
        <i class="iconfont icon-boy"></i>
        {{ boy }}
      </div>
      <i class="iconfont icon-love"></i>
      <div class="name">
        <i class="iconfont icon-girl"></i>
        {{ girl }}
      </div>
    </div>
  </div>
</template>

<script>
import "@/fonts/iconfont.css";
import "@/css/heart.css";
import "@/js/utils/snow";
import dayjs from "dayjs";
import duration from "dayjs/plugin/duration";
import "dayjs/locale/zh-cn";
dayjs.locale("zh-cn");
dayjs.extend(duration);
export default {
  name: "Home",
  metaInfo() {
    return {
      title: this.title
    };
  },
  methods: {
    getAllChangeTime() {
      // let now = dayjs();
      // let before = dayjs(this.time);
      // this.day = now.diff(before, "day");
      // console.log("now.diff(before)", now.diff(before));
      // this.h = now.diff(before).hour();
      // this.m = now.diff(before, "minute").minute();
      // this.s = now.diff(before, "second").second();
      const diffTime = dayjs.duration(dayjs() - dayjs(this.time));
      this.day = diffTime.days();
      this.h = diffTime.hours();
      this.m = diffTime.minutes();
      this.s = diffTime.seconds();
      // return `${day}天${hours}小时${minutes}分${seconds}秒`;
    }
  },
  data() {
    return {
      boy: "吴伟元",
      girl: "陈梦纯",
      time: "2022-09-03 20:00:00",
      day: "",
      h: "",
      m: "",
      s: ""
    };
  },
  computed: {
    days: function() {
      let now = dayjs();
      let before = dayjs(this.time);
      return now.diff(before, "day");
    },
    title: function() {
      return "在一起" + this.days + "天";
    }
  },
  mounted() {},
  beforeCreate() {
    setInterval(() => {
      this.getAllChangeTime();
    }, 1000);
  }
};
</script>

