/* eslint-disable */
window.addEventListener('load', function () {
    var body = document.getElementsByTagName("body")[0];
    var canvas = document.createElement("canvas");
    var container = document.createElement("div");

    container.style.position = "fixed";
    container.style.zIndex = -1;
    container.style.top = 0;
    container.style.left = 0;
    container.style.width = '100%';
    container.style.height = '100%';
    container.style.pointerEvents = 'none';
    container.appendChild(canvas);

    body.appendChild(container);

    var flower = new Image()
    flower.src = 'data:image/png;base64,';
    var ctx = canvas.getContext("2d");
    var W = container.clientWidth || container.innerWidth;
    var H = container.clientHeight || container.innerHeight;
    canvas.width = W;
    canvas.height = H;

    window.addEventListener('resize', function() {
        W = container.clientWidth || container.innerWidth;
        H = container.clientHeight || container.innerHeight;
        canvas.width = W;
        canvas.height = H;
    });

    // this.console.log(canvas.clientWidth, canvas.clientHeight)
    var mp = 50;
    var particles = [];
    for (var i = 0; i < mp; i++) {
        particles.push({
            x: Math.random() * W,
            y: Math.random() * H,
            r: Math.random() * 0.125 + 0.05,
            d: Math.random() * mp
        })
    }
    function draw() {
        ctx.clearRect(0, 0, W, H);
        for (var i = 0; i < mp; i++) {
            var p = particles[i];
            var imgScale = p.r * 0.8;
            ctx.drawImage(flower, 0, 0, flower.width, flower.height, p.x, p.y, flower.width * imgScale, flower.height * imgScale);
        }
        update();
    }

    var angle = 0;

    function update() {
        angle += 0.01;
        for (var i = 0; i < mp; i++) {
            var p = particles[i];
            p.y += Math.cos(angle + p.d) + 1 + p.r / 2;
            p.x += Math.sin(angle) * 2;
            if (p.x > W + 5 || p.x < -5 || p.y > H) {
                if (i % 3 > 0) {
                    particles[i] = {
                        x: Math.random() * W,
                        y: -10,
                        r: p.r,
                        d: p.d
                    };
                } else {
                    if (Math.sin(angle) > 0) {
                        particles[i] = {
                            x: -5,
                            y: Math.random() * H,
                            r: p.r,
                            d: p.d
                        };
                    } else {
                        particles[i] = {
                            x: W + 5,
                            y: Math.random() * H,
                            r: p.r,
                            d: p.d
                        };
                    }
                }
            }
        }
    }
    setInterval(draw, 33);
});



